@app.route('/login', methods=['POST'])
def login():
    """
    Step 1: Verify username and password.
    On success, generate MFA code and redirect to MFA verification.
    User is NOT granted access to protected resources until MFA is verified.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid request'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    # Input validation
    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    if len(username) > 128 or len(password) > 256:
        return jsonify({'error': 'Invalid input'}), 400

    # Allowlist: only alphanumeric usernames
    if not username.isalnum():
        return jsonify({'error': 'Invalid username format'}), 400

    # Rate limiting
    client_ip = request.remote_addr
    rate_key = f"{client_ip}:{username}"

    if not _check_rate_limit(LOGIN_ATTEMPTS, rate_key, MAX_LOGIN_ATTEMPTS):
        logger.warning(f"Rate limit exceeded for login: {username} from {client_ip}")
        return jsonify({'error': 'Too many login attempts. Please try again later.'}), 429

    # Verify credentials
    if not _verify_password(username, password):
        _record_attempt(LOGIN_ATTEMPTS, rate_key)
        logger.info(f"Failed login attempt for user: {username} from {client_ip}")
        return jsonify({'error': 'Invalid username or password'}), 401

    # Password verified - set up session for MFA step
    # CRITICAL: Do NOT set mfa_verified here. User must complete MFA.
    session.clear()
    session.regenerate = True  # Regenerate session ID to prevent fixation
    session['authenticated'] = True
    session['mfa_verified'] = False  # Explicitly false until MFA is completed
    session['username'] = username
    session['login_time'] = time.time()
    session['mfa_pending_since'] = time.time()

    # Generate and send MFA code
    mfa_code = _generate_mfa_code()
    code_hash = hashlib.sha256(mfa_code.encode('utf-8')).hexdigest()

    # Store hashed MFA code with expiry (never store plaintext)
    mfa_session_token = secrets.token_hex(32)
    MFA_PENDING[mfa_session_token] = {
        'username': username,
        'code_hash': code_hash,
        'created_at': time.time(),
        'attempts': 0,
    }
    session['mfa_session_token'] = mfa_session_token

    _send_mfa_code(username, mfa_code)
    _reset_attempts(LOGIN_ATTEMPTS, rate_key)

    logger.info(f"Password verified for user: {username}, MFA code sent")

    return jsonify({
        'message': 'Password verified. MFA code sent. Please verify to access protected resources.',
        'redirect': '/verify-mfa',
        'mfa_required': True,
    }), 200


@app.route('/verify-mfa', methods=['POST'])
@require_password_auth
def verify_mfa():
    """
    Step 2: Verify MFA code.
    Only after this step is the user granted access to protected resources.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid request'}), 400

    mfa_code = data.get('mfa_code', '').strip()

    # Input validation: MFA code must be exactly 6 digits
    if not mfa_code or len(mfa_code) != 6 or not mfa_code.isdigit():
        return jsonify({'error': 'Invalid MFA code format. Must be 6 digits.'}), 400

    username = session.get('username')
    mfa_session_token = session.get('mfa_session_token')

    if not username or not mfa_session_token:
        session.clear()
        return jsonify({'error': 'Invalid session. Please login again.'}), 401

    # Check if MFA session exists
    mfa_data = MFA_PENDING.get(mfa_session_token)
    if not mfa_data:
        session.clear()
        return jsonify({'error': 'MFA session expired. Please login again.'}), 401

    # Verify the MFA session belongs to this user
    if mfa_data['username'] != username:
        logger.warning(f"MFA session mismatch for user: {username}")
        session.clear()
        if mfa_session_token in MFA_PENDING:
            del MFA_PENDING[mfa_session_token]
        return jsonify({'error': 'Invalid session. Please login again.'}), 401

    # Check MFA code expiry
    if time.time() - mfa_data['created_at'] > MFA_CODE_EXPIRY:
        del MFA_PENDING[mfa_session_token]
        session.clear()
        logger.info(f"MFA code expired for user: {username}")
        return jsonify({'error': 'MFA code expired. Please login again.'}), 401

    # Rate limit MFA attempts
    if mfa_data['attempts'] >= MAX_MFA_ATTEMPTS:
        del MFA_PENDING[mfa_session_token]
        session.clear()
        logger.warning(f"Too many MFA attempts for user: {username}")
        return jsonify({'error': 'Too many MFA attempts. Please login again.'}), 429

    # Verify MFA code using constant-time comparison
    submitted_hash = hashlib.sha256(mfa_code.encode('utf-8')).hexdigest()
    if not hmac.compare_digest(submitted_hash, mfa_data['code_hash']):
        mfa_data['attempts'] += 1
        remaining = MAX_MFA_ATTEMPTS - mfa_data['attempts']
        logger.info(f"Failed MFA attempt for user: {username}, {remaining} attempts remaining")
        return jsonify({
            'error': 'Invalid MFA code',
            'attempts_remaining': remaining,
        }), 401

    # MFA verified successfully
    del MFA_PENDING[mfa_session_token]

    # Regenerate session to prevent fixation
    old_username = session['username']
    old_login_time = session['login_time']
    session.clear()
    session['authenticated'] = True
    session['mfa_verified'] = True  # NOW the user is fully authenticated
    session['username'] = old_username
    session['login_time'] = old_login_time
    session['mfa_verified_time'] = time.time()
    session.permanent = True

    logger.info(f"MFA verified successfully for user: {username}")

    return jsonify({
        'message': 'MFA verification successful. Access granted.',
        'redirect': '/dashboard',
    }), 200


