@require_password_auth
def resend_mfa():
    """Resend MFA code if the previous one expired or wasn't received."""
    username = session.get('username')
    old_token = session.get('mfa_session_token')

    if not username:
        session.clear()
        return jsonify({'error': 'Invalid session. Please login again.'}), 401

