# Cleanup expired MFA sessions periodically
def _cleanup_expired_mfa():
    """Remove expired MFA pending sessions."""
    now = time.time()
    expired_tokens = [
        token for token, data in MFA_PENDING.items()
        if now - data['created_at'] > MFA_CODE_EXPIRY * 2
    ]
    for token in expired_tokens:
        del MFA_PENDING[token]


